async function verifyToken(event) {
  if (!OKTA_ISSUER_URL || !OKTA_CLIENT_ID) {
    return { authenticated: true, claims: null };
  }

  // IAM-authenticated requests from AgentCore Gateway (via regional API Gateway
  // with AWS_IAM auth) — no Bearer token, but identity is in requestContext.
  // The regional API Gateway resource policy restricts access to the AgentCore
  // service principal, and the IAM role is scoped to GET /api/* only.
  const userArn = event.requestContext?.identity?.userArn || "";
  if (userArn.includes("agentcore-gateway")) {
    console.log(JSON.stringify({ message: "AgentCore IAM auth", userArn }));
    return { authenticated: true, claims: null, isAgentCore: true };
  }

  const authHeader = event.headers?.Authorization || event.headers?.authorization;
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    return { authenticated: false, error: "Missing or invalid Authorization header" };
  }

  const token = authHeader.slice(7);
  try {
    const jwks = getJWKS();
    const { payload } = await jwtVerify(token, jwks, {
      issuer: OKTA_ISSUER_URL,
      audience: OKTA_AUDIENCE,
    });
    return { authenticated: true, claims: payload };
  } catch (err) {
    console.warn(JSON.stringify({ message: "JWT verification failed", error: err.message }));
    return { authenticated: false, error: "Invalid or expired token" };
  }
}

